def add_all(*numbers):
    print(f'Numbers: {numbers}')  # tuple
    return sum(numbers)

print(add_all(1, 2, 3))
print(add_all(1, 2, 3, 4, 5, 6))

def first_last(*args):
    return args[0], args[-1]

print(first_last(10, 20, 30, 40, 50))

# Factorial
def factorial(n):
    if n <= 1: return 1
    return n * factorial(n-1)

print([factorial(i) for i in range(8)])

# Power
def power(base, exp):
    if exp == 0: return 1
    return base * power(base, exp-1)

print(power(2, 10))

# GCD (Euclidean algorithm)
def gcd(a, b):
    if b == 0: return a
    return gcd(b, a % b)

print(gcd(48, 18))

# Binary search recursive
def binary_search(arr, target, low, high):
    if low > high: return -1
    mid = (low + high) // 2
    if arr[mid] == target: return mid
    if arr[mid] < target: return binary_search(arr, target, mid+1, high)
    return binary_search(arr, target, low, mid-1)

arr = [1,3,5,7,9,11,13,15]
print(binary_search(arr, 7, 0, len(arr)-1))

# Palindrome check
def is_palindrome(s):
    s = s.lower().replace(' ', '')
    return s == s[::-1]

for word in ['racecar', 'hello', 'madam', 'python']:
    print(f'{word}: {is_palindrome(word)}')

# Count vowels
def count_vowels(s):
    return sum(1 for c in s.lower() if c in 'aeiou')

print(count_vowels('Hello World'))

# Reverse words
def reverse_words(s):
    return ' '.join(s.split()[::-1])

print(reverse_words('Hello World Python'))

# Check prime
def is_prime(n):
    if n < 2: return False
    for i in range(2, int(n**0.5)+1):
        if n % i == 0: return False
    return True

primes = [n for n in range(2, 50) if is_prime(n)]
print(primes)

# LCM
def lcm(a, b):
    from math import gcd
    return abs(a*b) // gcd(a,b)

print(lcm(12, 18))

# Digital root
def digital_root(n):
    while n >= 10:
        n = sum(int(d) for d in str(n))
    return n

print(digital_root(9875))
